solutions.javascript:
// Solution
function maxOnes(n) {
    let binary = n.toString(2);
    let max = 0;
    let count = 0;
    for (let i = 0; i < binary.length; i++) {
        if (binary[i] === '1') {
            count++;
            max = Math.max(max, count);
        } else {
            count = 0;
        }
    }
    return max;
}
